/**
 * Action Determination Stage
 *
 * Stage 9 of the EmailCategorizer pipeline. Determines actions (archive, mark as read, custom)
 * based on final labels, confidence scores, and action rules.
 *
 * This stage runs for ALL emails regardless of whether they went through AI classification:
 * - For rule-based emails: Uses confidence from multi-label selection (stage 7)
 * - For AI-classified emails: Uses confidence from AI classification (stage 8c)
 *
 * This stage is responsible for:
 * - Evaluating archive thresholds based on confidence scores
 * - Determining mark-as-read actions when archiving
 * - Applying custom category-specific actions
 * - Generating action reasoning for explainability
 */

import { z } from 'zod';
import { EmailMessage, ClassificationSession } from '../types';
import { ClassificationResult, FinalClassificationSummary } from '../types/classification-result';
import { validateEmailInput, validateSessionInput, validateConfigInput } from '../utils/validation';

// Zod schema for action determination configuration
export const ActionDeterminationConfigSchema = z.object({
  archiveThresholds: z.object({
    lowImportance: z.number().min(0).max(1),
    mediumImportance: z.number().min(0).max(1),
    highImportance: z.number().min(0).max(1),
  }),
  defaultArchiveThreshold: z.enum(['lowImportance', 'mediumImportance', 'highImportance']),
  actionSettings: z
    .object({
      archiveIfBelowThreshold: z.boolean(),
      markAsReadIfArchived: z.boolean(),
      applyCustomActions: z.boolean(),
    })
    .optional(),
  categoryActions: z.record(z.array(z.string())).optional(),
});

// Configuration interface for action determination
export interface ActionDeterminationConfig {
  archiveThresholds: {
    lowImportance: number;
    mediumImportance: number;
    highImportance: number;
  };
  defaultArchiveThreshold: 'lowImportance' | 'mediumImportance' | 'highImportance';
  actionSettings?: {
    archiveIfBelowThreshold: boolean;
    markAsReadIfArchived: boolean;
    applyCustomActions: boolean;
  };
  categoryActions?: Record<string, string[]>;
}

// Threshold evaluation details
export interface ThresholdEvaluation {
  thresholdType: string;
  thresholdUsed: number;
  confidenceScore: number;
  belowThreshold: boolean;
  evaluationReason: string;
}

// Action determination result
export interface ActionDeterminationResult {
  determinedActions: string[];
  actionReasoning: string;
  thresholdEvaluation?: ThresholdEvaluation;
  processingDurationMs: number;
}

/**
 * Action determination stage - Determines actions based on labels and confidence
 *
 * Canonical signature: (email, session, result, config) => Promise<void>
 */
export async function actionDeterminationStage(
  email: EmailMessage,
  session: ClassificationSession,
  result: ClassificationResult,
  config: ActionDeterminationConfig
): Promise<void> {
  const startTime = Date.now();
  const processingSteps: string[] = [];

  // Validate inputs
  validateInputs(email, session, result, config);
  processingSteps.push('Input validation completed');

  // Extract assigned labels from result
  const primaryCategory = result.primaryCategory;
  const secondaryCategories = result.secondaryCategories || [];
  const confidence = result.confidence || 0;

  if (!primaryCategory) {
    throw new Error('Cannot determine actions: primaryCategory not set in result');
  }

  processingSteps.push(`Labels: primary=${primaryCategory}, secondary=[${secondaryCategories.join(', ')}]`);

  // Determine actions based on confidence and category rules
  const { determinedActions, actionReasoning } = determineActions(
    { primary: primaryCategory, secondary: secondaryCategories },
    confidence,
    config,
    processingSteps
  );

  processingSteps.push(`Actions determined: [${determinedActions.join(', ')}]`);

  // Store in result
  result.determinedActions = determinedActions;

  // Generate final classification summary (consistent output regardless of AI path)
  result.finalClassificationSummary = generateFinalSummary(result, determinedActions);

  // Defensive check for explainabilityTrace initialization
  if (!result.explainabilityTrace) {
    throw new Error('CRITICAL: explainabilityTrace is not initialized in result object');
  }

  // Append action reasoning to explainability trace
  const existingReason = result.explainabilityTrace.finalDecisionReason || '';
  result.explainabilityTrace.finalDecisionReason = existingReason
    ? `${existingReason}; Actions: ${actionReasoning}`
    : `Actions: ${actionReasoning}`;

  // Track processing time
  result.explainabilityTrace.stageTimings = result.explainabilityTrace.stageTimings || {};
  result.explainabilityTrace.stageTimings['actionDetermination'] = Date.now() - startTime;

  // Update result processing duration
  result.processingDurationMs += Date.now() - startTime;
}

/**
 * Validate input parameters
 */
function validateInputs(
  email: EmailMessage,
  session: ClassificationSession,
  result: ClassificationResult,
  config: ActionDeterminationConfig
): void {
  validateEmailInput(email);
  validateSessionInput(session);
  validateConfigInput(config);

  if (!result) {
    throw new Error('Classification result is required');
  }

  if (!config.archiveThresholds || typeof config.archiveThresholds !== 'object') {
    throw new Error('Invalid configuration: archiveThresholds are required');
  }
}

/**
 * Determine actions based on labels, confidence, and action rules
 */
function determineActions(
  assignedLabels: { primary: string; secondary: string[] },
  confidence: number,
  config: ActionDeterminationConfig,
  processingSteps: string[]
): {
  determinedActions: string[];
  actionReasoning: string;
  thresholdEvaluation?: ThresholdEvaluation;
} {
  const determinedActions: string[] = [];
  const actionReasons: string[] = [];

  // Get action determination settings with defaults
  const actionSettings = config.actionSettings || {
    archiveIfBelowThreshold: true,
    markAsReadIfArchived: false,
    applyCustomActions: false,
  };

  // Evaluate archive threshold
  let thresholdEvaluation: ThresholdEvaluation | undefined;

  if (actionSettings.archiveIfBelowThreshold) {
    const thresholdType = config.defaultArchiveThreshold;
    const thresholdValue = config.archiveThresholds[thresholdType];
    const belowThreshold = confidence < thresholdValue;

    thresholdEvaluation = {
      thresholdType,
      thresholdUsed: thresholdValue,
      confidenceScore: confidence,
      belowThreshold,
      evaluationReason: `Confidence ${confidence.toFixed(2)} ${belowThreshold ? '<' : '>='} ${thresholdType} threshold ${thresholdValue}`,
    };

    processingSteps.push(
      `Threshold evaluation: ${confidence.toFixed(2)} ${belowThreshold ? 'below' : 'above'} ${thresholdType} (${thresholdValue})`
    );

    if (belowThreshold) {
      determinedActions.push('archive');
      actionReasons.push(`Confidence ${confidence.toFixed(2)} below threshold ${thresholdValue}`);
      processingSteps.push('Action: archive (below threshold)');

      // Mark as read if archiving
      if (actionSettings.markAsReadIfArchived) {
        determinedActions.push('markAsRead');
        actionReasons.push('Mark as read when archiving');
        processingSteps.push('Action: markAsRead (archiving)');
      }
    }
  }

  // Apply custom category-specific actions
  if (actionSettings.applyCustomActions && config.categoryActions) {
    const allCategories = [assignedLabels.primary, ...assignedLabels.secondary];

    for (const category of allCategories) {
      const categoryActions = config.categoryActions[category];
      if (categoryActions && Array.isArray(categoryActions)) {
        for (const action of categoryActions) {
          if (!determinedActions.includes(action)) {
            determinedActions.push(action);
            actionReasons.push(`Category ${category} action: ${action}`);
            processingSteps.push(`Action: ${action} (from category ${category})`);
          }
        }
      }
    }
  }

  const actionReasoning = actionReasons.length > 0 ? actionReasons.join('; ') : 'No actions determined';

  return { determinedActions, actionReasoning, thresholdEvaluation };
}

/**
 * Generate final classification summary
 *
 * Creates a consistent summary of classification results regardless of whether
 * the email went through rule-based or AI-enhanced classification path.
 * This provides a unified interface for downstream consumers.
 */
function generateFinalSummary(result: ClassificationResult, determinedActions: string[]): FinalClassificationSummary {
  // Extract primary label from selectedLabels
  const primaryLabel = result.selectedLabels.find((label) => label.isPrimary) || result.selectedLabels[0];

  // Calculate confidence range
  const confidences = result.selectedLabels.map((label) => label.confidence);
  const confidenceRange: [number, number] =
    confidences.length > 0 ? [Math.min(...confidences), Math.max(...confidences)] : [0, 0];

  // Determine classification path
  const classificationPath: 'ruleBased' | 'aiEnhanced' = result.aiRoutingUsed ? 'aiEnhanced' : 'ruleBased';

  return {
    totalLabels: result.selectedLabels.length,
    primaryCategory: primaryLabel?.category || result.primaryCategory || 'uncategorized',
    primarySubtype: primaryLabel?.subtype || null,
    confidenceRange,
    classificationPath,
    selectedLabels: result.selectedLabels,
    determinedActions,
    processingDurationMs: result.processingDurationMs,
  };
}

